package com.example.recipetracker;

import android.os.Bundle;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.appcompat.widget.Toolbar;

import com.example.recipetracker.database.Recipe;
import com.example.recipetracker.database.RecipeDatabase;
import com.example.recipetracker.util.SessionManager;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;

/**
 * AddEditRecipeActivity — Add a new recipe OR edit an existing one.

 * To open for ADDING a new recipe:
 *   startActivity(new Intent(this, AddEditRecipeActivity.class));
 *
 * To open for EDITING an existing recipe:
 *   Intent intent = new Intent(this, AddEditRecipeActivity.class);
 *   intent.putExtra(AddEditRecipeActivity.EXTRA_RECIPE_ID, recipe.id);
 *   startActivity(intent);
 *
 * What to build here:
 *  - Form fields: title, ingredients, steps, category, prep time
 *  - Save button — validates fields then inserts/updates DB
 *  - Delete button — only shown when editing
 *  - Pre-fills fields when editing
 */
public class AddEditRecipeActivity extends AppCompatActivity {

    public static final String EXTRA_RECIPE_ID = "recipe_id";

    private TextInputEditText etTitle, etIngredients, etSteps, etCategory, etPrepTime;
    private MaterialButton btnSave, btnDelete;

    private RecipeDatabase db;
    private SessionManager session;

    /** null = adding new recipe, non-null = editing existing */
    private Recipe recipeToEdit = null;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_add_edit_recipe);

        db      = RecipeDatabase.getInstance(this);
        session = new SessionManager(this);

        // Wire up views
        Toolbar toolbar = findViewById(R.id.toolbar);
        etTitle         = findViewById(R.id.et_title);
        etIngredients   = findViewById(R.id.et_ingredients);
        etSteps         = findViewById(R.id.et_steps);
        etCategory      = findViewById(R.id.et_category);
        etPrepTime      = findViewById(R.id.et_prep_time);
        btnSave         = findViewById(R.id.btn_save);
        btnDelete       = findViewById(R.id.btn_delete);

        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) getSupportActionBar().setDisplayHomeAsUpEnabled(true);

        // Check if we're editing
        int recipeId = getIntent().getIntExtra(EXTRA_RECIPE_ID, -1);
        if (recipeId != -1) {
            // Edit mode: load recipe and pre-fill fields
            if (getSupportActionBar() != null) getSupportActionBar().setTitle(R.string.edit_recipe_title);
            btnDelete.setVisibility(android.view.View.VISIBLE);

            new Thread(() -> {
                recipeToEdit = db.recipeDao().getById(recipeId);
                runOnUiThread(this::prefillFields);
            }).start();
        } else {
            // Add mode
            if (getSupportActionBar() != null) getSupportActionBar().setTitle(R.string.add_recipe_title);
            btnDelete.setVisibility(android.view.View.GONE);
        }

        btnSave.setOnClickListener(v -> saveRecipe());
        btnDelete.setOnClickListener(v -> deleteRecipe());
    }

    /** Pre-fill all form fields when editing */
    private void prefillFields() {
        if (recipeToEdit == null) return;
        etTitle.setText(recipeToEdit.title);
        etIngredients.setText(recipeToEdit.ingredients);
        etSteps.setText(recipeToEdit.steps);
        etCategory.setText(recipeToEdit.category);
        etPrepTime.setText(recipeToEdit.prepTime);
    }

    /** Validate → save to DB → close */
    private void saveRecipe() {
        String title       = getText(etTitle);
        String ingredients = getText(etIngredients);
        String steps       = getText(etSteps);
        String category    = getText(etCategory);
        String prepTime    = getText(etPrepTime);

        // Basic validation
        if (title.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_name, Toast.LENGTH_SHORT).show();
            return;
        }
        if (ingredients.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_ingredients, Toast.LENGTH_SHORT).show();
            return;
        }
        if (steps.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_steps, Toast.LENGTH_SHORT).show();
            return;
        }

        new Thread(() -> {
            if (recipeToEdit == null) {
                // INSERT new
                Recipe newRecipe = new Recipe(
                        title, ingredients, steps,
                        category, prepTime, session.getUsername()
                );
                db.recipeDao().insert(newRecipe);
            } else {
                // UPDATE existing
                recipeToEdit.title       = title;
                recipeToEdit.ingredients = ingredients;
                recipeToEdit.steps       = steps;
                recipeToEdit.category    = category;
                recipeToEdit.prepTime    = prepTime;
                db.recipeDao().update(recipeToEdit);
            }
            runOnUiThread(() -> {
                Toast.makeText(this, R.string.saved_success, Toast.LENGTH_SHORT).show();
                finish();
            });
        }).start();
    }

    /** Delete recipe and go back */
    private void deleteRecipe() {
        if (recipeToEdit == null) return;
        new Thread(() -> {
            db.recipeDao().delete(recipeToEdit);
            runOnUiThread(() -> {
                Toast.makeText(this, R.string.deleted_success, Toast.LENGTH_SHORT).show();
                finish();
            });
        }).start();
    }

    /** Helper — safely get trimmed text from an EditText */
    private String getText(TextInputEditText et) {
        return et.getText() != null ? et.getText().toString().trim() : "";
    }

    @Override
    public boolean onSupportNavigateUp() {
        finish();
        return true;
    }
}

package com.example.recipetracker;

import android.os.Bundle;
import android.widget.ArrayAdapter;
import android.widget.Spinner;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.appcompat.widget.Toolbar;

import com.example.recipetracker.database.Recipe;
import com.example.recipetracker.database.RecipeDatabase;
import com.example.recipetracker.util.SessionManager;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;

/**
 * AddEditRecipeActivity — Add a new recipe OR edit an existing one.

 * To open for ADDING a new recipe:
 *   startActivity(new Intent(this, AddEditRecipeActivity.class));
 *
 * To open for EDITING an existing recipe:
 *   Intent intent = new Intent(this, AddEditRecipeActivity.class);
 *   intent.putExtra(AddEditRecipeActivity.EXTRA_RECIPE_ID, recipe.id);
 *   startActivity(intent);
 *
 * What to build here:
 *  - Form fields: title, ingredients, steps, category, prep time
 *  - Save button — validates fields then inserts/updates DB
 *  - Delete button — only shown when editing
 *  - Pre-fills fields when editing
 */
public class AddEditRecipeActivity extends AppCompatActivity {

    public static final String EXTRA_RECIPE_ID = "recipe_id";

    private TextInputEditText etTitle, etIngredients, etSteps, etPrepTime;
    private Spinner spinnerCategory;
    private MaterialButton btnSave, btnDelete;

    private RecipeDatabase db;
    private SessionManager session;

    /** null = adding new recipe, non-null = editing existing */
    private Recipe recipeToEdit = null;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_add_edit_recipe);

        db      = RecipeDatabase.getInstance(this);
        session = new SessionManager(this);

        // Wire up views
        Toolbar toolbar = findViewById(R.id.toolbar);
        etTitle         = findViewById(R.id.et_title);
        etIngredients   = findViewById(R.id.et_ingredients);
        etSteps         = findViewById(R.id.et_steps);
        spinnerCategory = findViewById(R.id.spinner_category);
        etPrepTime      = findViewById(R.id.et_prep_time);
        btnSave         = findViewById(R.id.btn_save);
        btnDelete       = findViewById(R.id.btn_delete);

        // Setup category spinner with options
        String[] categories = {"Breakfast", "Lunch", "Dinner"};
        ArrayAdapter<String> adapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_item, categories);
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        spinnerCategory.setAdapter(adapter);

        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) getSupportActionBar().setDisplayHomeAsUpEnabled(true);

        // Check if we're editing
        int recipeId = getIntent().getIntExtra(EXTRA_RECIPE_ID, -1);
        if (recipeId != -1) {
            // Edit mode: load recipe and pre-fill fields
            if (getSupportActionBar() != null) getSupportActionBar().setTitle(R.string.edit_recipe_title);
            btnDelete.setVisibility(android.view.View.VISIBLE);

            new Thread(() -> {
                recipeToEdit = db.recipeDao().getById(recipeId);
                runOnUiThread(this::prefillFields);
            }).start();
        } else {
            // Add mode
            if (getSupportActionBar() != null) getSupportActionBar().setTitle(R.string.add_recipe_title);
            btnDelete.setVisibility(android.view.View.GONE);
        }

        btnSave.setOnClickListener(v -> saveRecipe());
        btnDelete.setOnClickListener(v -> deleteRecipe());
    }

    /** Pre-fill all form fields when editing */
    private void prefillFields() {
        if (recipeToEdit == null) return;
        etTitle.setText(recipeToEdit.title);
        etIngredients.setText(recipeToEdit.ingredients);
        etSteps.setText(recipeToEdit.steps);
        etPrepTime.setText(recipeToEdit.prepTime);

        // Set spinner selection to the saved category
        ArrayAdapter<String> adapter = (ArrayAdapter<String>) spinnerCategory.getAdapter();
        if (adapter != null && recipeToEdit.category != null) {
            int position = adapter.getPosition(recipeToEdit.category);
            spinnerCategory.setSelection(position >= 0 ? position : 0);
        }
    }

    /** Validate → save to DB → close */
    private void saveRecipe() {
        String title       = getText(etTitle);
        String ingredients = getText(etIngredients);
        String steps       = getText(etSteps);
        String category    = (String) spinnerCategory.getSelectedItem();
        String prepTime    = getText(etPrepTime);

        // Basic validation
        if (title.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_name, Toast.LENGTH_SHORT).show();
            return;
        }
        if (ingredients.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_ingredients, Toast.LENGTH_SHORT).show();
            return;
        }
        if (steps.isEmpty()) {
            Toast.makeText(this, R.string.error_empty_steps, Toast.LENGTH_SHORT).show();
            return;
        }
        if (prepTime.isEmpty()) {
            Toast.makeText(this, "Please enter a prep time in minutes", Toast.LENGTH_SHORT).show();
            return;
        }

        new Thread(() -> {
            if (recipeToEdit == null) {
                // INSERT new
                Recipe newRecipe = new Recipe(
                        title, ingredients, steps,
                        category, prepTime, session.getUsername()
                );
                db.recipeDao().insert(newRecipe);
            } else {
                // UPDATE existing
                recipeToEdit.title       = title;
                recipeToEdit.ingredients = ingredients;
                recipeToEdit.steps       = steps;
                recipeToEdit.category    = category;
                recipeToEdit.prepTime    = prepTime;
                db.recipeDao().update(recipeToEdit);
            }
            runOnUiThread(() -> {
                Toast.makeText(this, R.string.saved_success, Toast.LENGTH_SHORT).show();
                finish();
            });
        }).start();
    }

    /** Delete recipe and go back */
    private void deleteRecipe() {
        if (recipeToEdit == null) return;
        new Thread(() -> {
            db.recipeDao().delete(recipeToEdit);
            runOnUiThread(() -> {
                Toast.makeText(this, R.string.deleted_success, Toast.LENGTH_SHORT).show();
                finish();
            });
        }).start();
    }

    /** Helper — safely get trimmed text from an EditText */
    private String getText(TextInputEditText et) {
        return et.getText() != null ? et.getText().toString().trim() : "";
    }

    @Override
    public boolean onSupportNavigateUp() {
        finish();
        return true;
    }
}

package com.example.recipetracker;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.View;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.recipetracker.database.RecipeDatabase;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.google.android.material.textfield.TextInputEditText;

import java.util.Calendar;

/**
 * MainActivity — Home Screen
 *
 * What to build here:
 *  - RecyclerView grid of recipe cards
 *  - Search bar that filters results live
 *  - FAB to go to AddEditRecipeActivity
 *  - Bottom navigation (same on every screen)
 *  - Dynamic greeting based on time of day
 *  - Empty state when no recipes exist
 */
public class MainActivity extends AppCompatActivity {

    private RecyclerView recyclerView;
    private TextInputEditText searchBar;
    private FloatingActionButton fabAdd;
    private BottomNavigationView bottomNav;
    private LinearLayout emptyStateContainer;
    private TextView greetingText;

    // TODO: create a RecipeAdapter class for the RecyclerView
    // private RecipeAdapter adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Wire up views
        recyclerView = findViewById(R.id.recycler_recipes);
        searchBar = findViewById(R.id.edit_search);
        fabAdd = findViewById(R.id.fab_add_recipe);
        bottomNav = findViewById(R.id.bottom_navigation);
        emptyStateContainer = findViewById(R.id.empty_state_container);
        greetingText = findViewById(R.id.tv_greeting);

        // Set dynamic greeting based on time of day
        setDynamicGreeting();

        // Grid: 2 columns
        recyclerView.setLayoutManager(new GridLayoutManager(this, 2));

        // TODO: Set up adapter and attach to recyclerView

        // Load all recipes from DB and show them
        RecipeDatabase.getInstance(this)
                .recipeDao()
                .getAllRecipes()
                .observe(this, recipes -> {
                    // TODO: adapter.setRecipes(recipes);
                    updateEmptyState(recipes != null && !recipes.isEmpty());
                });

        // Live search — fires every time the user types
        searchBar.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) {
                String query = s.toString().trim();
                if (query.isEmpty()) {
                    // Show all recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .getAllRecipes()
                            .observe(MainActivity.this, recipes -> {
                                // TODO: adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                } else {
                    // Search recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .searchRecipes(query)
                            .observe(MainActivity.this, recipes -> {
                                // TODO: adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                }
            }
            @Override public void afterTextChanged(Editable s) {}
        });

        // FAB → Add recipe screen
        fabAdd.setOnClickListener(v -> {
            Intent intent = new Intent(this, AddEditRecipeActivity.class);
            startActivity(intent);
        });

        // Bottom nav
        setupBottomNav();
    }

    /**
     * Set greeting text based on current time of day
     */
    private void setDynamicGreeting() {
        Calendar calendar = Calendar.getInstance();
        int hour = calendar.get(Calendar.HOUR_OF_DAY);

        int greetingResId;
        if (hour >= 5 && hour < 12) {
            greetingResId = R.string.home_greeting_morning;
        } else if (hour >= 12 && hour < 17) {
            greetingResId = R.string.home_greeting_afternoon;
        } else {
            greetingResId = R.string.home_greeting_evening;
        }

        greetingText.setText(greetingResId);
    }

    /**
     * Show/hide empty state based on whether recipes exist
     */
    private void updateEmptyState(boolean hasRecipes) {
        if (hasRecipes) {
            recyclerView.setVisibility(View.VISIBLE);
            emptyStateContainer.setVisibility(View.GONE);
        } else {
            recyclerView.setVisibility(View.GONE);
            emptyStateContainer.setVisibility(View.VISIBLE);
        }
    }

    private void setupBottomNav() {
        bottomNav.setSelectedItemId(R.id.nav_home);
        bottomNav.setOnItemSelectedListener(item -> {
            int id = item.getItemId();
            if (id == R.id.nav_home) {
                return true; // already here
            } else if (id == R.id.nav_discover) {
                startActivity(new Intent(this, DiscoverActivity.class));
                overridePendingTransition(0, 0);
                return true;
            } else if (id == R.id.nav_favourites) {
                startActivity(new Intent(this, FavouritesActivity.class));
                overridePendingTransition(0, 0);
                return true;
            }
            return false;
        });
    }
}

package com.example.recipetracker;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.View;
import android.widget.LinearLayout;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.recipetracker.database.RecipeDatabase;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.google.android.material.textfield.TextInputEditText;

import java.util.Calendar;

/**
 * MainActivity — Home Screen
 *
 * What to build here:
 *  - RecyclerView grid of recipe cards
 *  - Search bar that filters results live
 *  - FAB to go to AddEditRecipeActivity
 *  - Bottom navigation (same on every screen)
 *  - Dynamic greeting based on time of day
 *  - Empty state when no recipes exist
 */
public class MainActivity extends AppCompatActivity {

    private RecyclerView recyclerView;
    private TextInputEditText searchBar;
    private FloatingActionButton fabAdd;
    private BottomNavigationView bottomNav;
    private LinearLayout emptyStateContainer;
    private TextView greetingText;
    private RecipeAdapter adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Wire up views
        recyclerView = findViewById(R.id.recycler_recipes);
        searchBar = findViewById(R.id.edit_search);
        fabAdd = findViewById(R.id.fab_add_recipe);
        bottomNav = findViewById(R.id.bottom_navigation);
        emptyStateContainer = findViewById(R.id.empty_state_container);
        greetingText = findViewById(R.id.tv_greeting);

        // Set dynamic greeting based on time of day
        setDynamicGreeting();

        // Grid: 2 columns
        recyclerView.setLayoutManager(new GridLayoutManager(this, 2));

        // Set up adapter with click listener
        adapter = new RecipeAdapter(recipe -> {
            Intent intent = new Intent(this, RecipeDetailActivity.class);
            intent.putExtra(RecipeDetailActivity.EXTRA_RECIPE_ID, recipe.id);
            startActivity(intent);
        });
        recyclerView.setAdapter(adapter);

        // Load all recipes from DB and show them
        RecipeDatabase.getInstance(this)
                .recipeDao()
                .getAllRecipes()
                .observe(this, recipes -> {
                    adapter.setRecipes(recipes);
                    updateEmptyState(recipes != null && !recipes.isEmpty());
                });

        // Live search — fires every time the user types
        searchBar.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) {
                String query = s.toString().trim();
                if (query.isEmpty()) {
                    // Show all recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .getAllRecipes()
                            .observe(MainActivity.this, recipes -> {
                                adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                } else {
                    // Search recipes
                    RecipeDatabase.getInstance(MainActivity.this)
                            .recipeDao()
                            .searchRecipes(query)
                            .observe(MainActivity.this, recipes -> {
                                adapter.setRecipes(recipes);
                                updateEmptyState(recipes != null && !recipes.isEmpty());
                            });
                }
            }
            @Override public void afterTextChanged(Editable s) {}
        });

        // FAB → Add recipe screen
        fabAdd.setOnClickListener(v -> {
            Intent intent = new Intent(this, AddEditRecipeActivity.class);
            startActivity(intent);
        });

        // Bottom nav
        setupBottomNav();
    }

    /**
     * Set greeting text based on current time of day
     */
    private void setDynamicGreeting() {
        Calendar calendar = Calendar.getInstance();
        int hour = calendar.get(Calendar.HOUR_OF_DAY);

        int greetingResId;
        if (hour >= 5 && hour < 12) {
            greetingResId = R.string.home_greeting_morning;
        } else if (hour >= 12 && hour < 17) {
            greetingResId = R.string.home_greeting_afternoon;
        } else {
            greetingResId = R.string.home_greeting_evening;
        }

        greetingText.setText(greetingResId);
    }

    /**
     * Show/hide empty state based on whether recipes exist
     */
    private void updateEmptyState(boolean hasRecipes) {
        if (hasRecipes) {
            recyclerView.setVisibility(View.VISIBLE);
            emptyStateContainer.setVisibility(View.GONE);
        } else {
            recyclerView.setVisibility(View.GONE);
            emptyStateContainer.setVisibility(View.VISIBLE);
        }
    }

    private void setupBottomNav() {
        bottomNav.setSelectedItemId(R.id.nav_home);
        bottomNav.setOnItemSelectedListener(item -> {
            int id = item.getItemId();
            if (id == R.id.nav_home) {
                return true; // already here
            } else if (id == R.id.nav_discover) {
                startActivity(new Intent(this, DiscoverActivity.class));
                overridePendingTransition(0, 0);
                return true;
            } else if (id == R.id.nav_favourites) {
                startActivity(new Intent(this, FavouritesActivity.class));
                overridePendingTransition(0, 0);
                return true;
            }
            return false;
        });
    }
}

package com.example.recipetracker;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.recipetracker.database.Recipe;

import java.util.ArrayList;
import java.util.List;

/**
 * RecipeAdapter — Adapter for displaying recipes in RecyclerView
 */
public class RecipeAdapter extends RecyclerView.Adapter<RecipeAdapter.RecipeViewHolder> {

    private List<Recipe> recipes = new ArrayList<>();
    private OnRecipeClickListener listener;

    public interface OnRecipeClickListener {
        void onRecipeClick(Recipe recipe);
    }

    public RecipeAdapter(OnRecipeClickListener listener) {
        this.listener = listener;
    }

    @NonNull
    @Override
    public RecipeViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_recipe_card, parent, false);
        return new RecipeViewHolder(view, listener);
    }

    @Override
    public void onBindViewHolder(@NonNull RecipeViewHolder holder, int position) {
        Recipe recipe = recipes.get(position);
        holder.bind(recipe);
    }

    @Override
    public int getItemCount() {
        return recipes.size();
    }

    /**
     * Update the list of recipes
     */
    public void setRecipes(List<Recipe> newRecipes) {
        this.recipes = newRecipes != null ? newRecipes : new ArrayList<>();
        notifyDataSetChanged();
    }

    /**
     * ViewHolder for recipe items
     */
    public static class RecipeViewHolder extends RecyclerView.ViewHolder {

        private TextView tvTitle, tvCategory, tvPrepTime;
        private OnRecipeClickListener listener;

        public RecipeViewHolder(@NonNull View itemView, OnRecipeClickListener listener) {
            super(itemView);
            this.listener = listener;
            tvTitle = itemView.findViewById(R.id.tv_card_title);
            tvCategory = itemView.findViewById(R.id.tv_card_category);
            tvPrepTime = itemView.findViewById(R.id.tv_card_prep_time);
        }

        public void bind(Recipe recipe) {
            tvTitle.setText(recipe.title);
            tvCategory.setText(recipe.category);
            tvPrepTime.setText(recipe.prepTime + " min");

            itemView.setOnClickListener(v -> {
                if (listener != null) {
                    listener.onRecipeClick(recipe);
                }
            });
        }
    }
}
